svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var ns          = 'http://www.w3.org/2000/svg';
    var dataLayerEl = svgEl.querySelector('#data-layer');
    var dotsLayer   = svgEl.querySelector('#dots-layer');
    var hitLayer    = svgEl.querySelector('#hit-layer');
    var tipLayer    = svgEl.querySelector('#tip-layer');
    var defs        = svgEl.querySelector('defs');
    var plot        = { x:68, y:100, width:772, height:400 };
    var plotL = 42, plotR = 840, plotT = 100;

    var series = [
      { id:1, cls:'series-1', label:'Cyan',    vals:[100,119,130,146,151,175,185,210], ys:[322.2,288.4,268.9,240.4,231.6,188.9,171.1,126.7] },
      { id:2, cls:'series-2', label:'Emerald', vals:[68,81,89,98,99,114,117,138],      ys:[379.1,356.0,341.8,325.8,324.0,297.3,292.0,254.7] },
      { id:3, cls:'series-3', label:'Amber',   vals:[40,50,54,58,55,65,62,76],         ys:[428.9,411.1,404.0,396.9,402.2,384.4,389.8,364.9] },
      { id:4, cls:'series-4', label:'Rose',    vals:[22,28,29,29,30,37,31,41],         ys:[460.9,450.2,448.4,448.4,446.7,434.2,444.9,427.1] },
      { id:5, cls:'series-5', label:'Violet',  vals:[10,13,11,15,13,17,15,19],         ys:[482.2,476.9,480.4,473.3,476.9,469.8,473.3,466.2] }
    ];
    var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
    var xs = [68,171,274,377,480,583,686,789];
    var totals = xs.map(function(_, qi) {
      return series.reduce(function(sum, s) { return sum + s.vals[qi]; }, 0);
    });
    var dotTravelSeconds = 0.96;
    var revealTiming = ctx.getStaggerTiming(series.length, { duration: 1.2 }, svgEl);
    var el = ctx.el;

    [
      { selector:'#band-1-2', id:1 },
      { selector:'#band-2-3', id:2 },
      { selector:'#band-3-4', id:3 },
      { selector:'#band-4-5', id:4 },
      { selector:'#band-base', id:5 }
    ].forEach(function(band, i) {
      var area = svgEl.querySelector(band.selector);
      var line = svgEl.querySelector('#line-' + band.id);
      var revealDelay = ctx.getStaggerDelay(i, series.length, null, svgEl);
      if (area) {
        ctx.initAreaClipReveal({
          defs: defs,
          area: area,
          clipId: 'line-stack-reveal-' + band.id,
          x: plot.x,
          y: plot.y,
          width: plot.width,
          height: plot.height,
          delay: revealDelay,
          duration: 1200
        });
      }
      if (line) ctx.initStrokeReveal(line, { delay: revealDelay });
    });

    series.forEach(function(s) {
      xs.forEach(function(x, qi) {
        var y = s.ys[qi];
        var key = s.id + '_' + qi;
        var delaySeconds = ctx.getStaggerDelay(s.id - 1, series.length, null, svgEl) + qi * (dotTravelSeconds / Math.max(1, xs.length - 1));

        var dg = el('g', {'class':'dot-g', id:'d'+key});
        var inner = el('g', {'class':'dot-inner', style:'transform-origin:'+x+'px '+y+'px'});
        ctx.animateAndMarkVisible(inner, 'popDot 0.35s cubic-bezier(0.34,1.4,0.64,1) ' + delaySeconds + 's');
        inner.appendChild(el('circle', { cx:x, cy:y, r:5, 'class':s.cls, stroke:'none' }));
        dg.appendChild(inner);
        dotsLayer.appendChild(dg);

        dotsLayer.appendChild(el('circle', { cx:x, cy:y, r:4, 'class':'col-dot ' + s.cls, 'data-col':qi, stroke:'none' }));
      });
    });

    // Activate the nearest series for a hovered quarter and sync stacked-only dot states.
    function setColumnHover(qi, mouseY) {
      var bestSid = ctx.getNearestSeriesIdAtColumn(series, qi, mouseY);
      dataLayerEl.classList.add('hovering');
      ctx.setSeriesHoverState({
        activeSid: bestSid,
        seriesIds: series.map(function(s) { return s.id; }),
        pointIndices: [qi],
        lineSelector: '#line-{id}',
        areaSelector: '.area-path[data-series="{id}"]',
        dotSelector: '#d{id}_{qi} .dot-inner'
      });
      dotsLayer.querySelectorAll('.col-dot').forEach(function(dot) { dot.classList.remove('active'); });
      dotsLayer.querySelectorAll('.col-dot[data-col="'+qi+'"]').forEach(function(dot) {
        dot.classList.toggle('active', dot.getAttribute('class').indexOf('series-'+bestSid) !== -1);
      });
    }

    // Clear stacked-line hover state for both the series traces and the column markers.
    function clearColumnHover() {
      dataLayerEl.classList.remove('hovering');
      ctx.setSeriesHoverState({
        activeSid: null,
        seriesIds: series.map(function(s) { return s.id; }),
        pointCount: xs.length,
        lineSelector: '#line-{id}',
        areaSelector: '.area-path[data-series="{id}"]',
        dotSelector: '#d{id}_{qi} .dot-inner'
      });
      dotsLayer.querySelectorAll('.col-dot').forEach(function(dot) { dot.classList.remove('active'); });
    }

    ctx.initStackedColumnHover({
      xs: xs,
      quarters: quarters,
      series: series,
      totals: totals,
      tipLayer: tipLayer,
      hitLayer: hitLayer,
      plotL: plotL,
      plotR: plotR,
      plotT: plotT,
      plotB: 500,
      anchorY: 300,
      hitTop: 100,
      hitHeight: 400,
      hitHalfWidth: 56,
      hitMinX: 68,
      hitMaxX: 832,
      onEnter: function(qi, sp, tipG, ch) {
        setColumnHover(qi, sp.y);
        ctx.setOpacity(tipG, 1);
        ctx.setOpacity(ch, 1);
      },
      onMove: function(qi, sp) {
        setColumnHover(qi, sp.y);
      },
      onLeave: function(qi, tipG, ch) {
        clearColumnHover();
        ctx.setOpacity(tipG, null);
        ctx.setOpacity(ch, null);
      }
    });

    var dotLastDelay = ctx.getStaggerDelay(series.length - 1, series.length, null, svgEl) + dotTravelSeconds;
    var readyDelayMs = Math.max(revealTiming.readyDelayMs, (dotLastDelay + 0.35 + 0.1) * 1000);
    setTimeout(function(){ dataLayerEl.classList.add('ready'); }, readyDelayMs);
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
